INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '579bbaa3-6326-4bfb-bd3a-867724cb5eaa',
  '00000000-0000-0000-0000-000000000001',
  $escape$vitest Integration Testing — Mock at the Network Boundary, Not the Component Boundary$escape$,
  $escape$Integration tests in vitest shine when you render a component tree together and only mock what crosses a real boundary — network calls, browser APIs, timers. The mistake most teams make is mocking child components, which guts the test's value. If `<UserProfile>` renders `<Avatar>` and `<ActivityFeed>`, test them as a unit. Use `msw` with vitest's `setupFiles` to intercept HTTP at the fetch level instead. Configure `server.use(http.get('/api/user/:id', ...))` in a `beforeEach`, then render the parent with `@testing-library/react`. Assertions target real DOM output — `getByRole`, `findByText` — not internal state. Vitest's `vi.mock` is still the right tool for non-HTTP boundaries: browser storage, `crypto`, `IntersectionObserver`. Use `vi.stubGlobal('IntersectionObserver', mockImpl)` rather than polluting the module graph. The rule: mock the protocol, not the component. Your integration test should survive a full component refactor without changing a single assertion.$escape$,
  $escape$// vitest.setup.ts
import { server } from './mocks/server'
beforeAll(() => server.listen({ onUnhandledRequest: 'error' }))
afterEach(() => server.resetHandlers())
afterAll(() => server.close())

// UserProfile.test.tsx
it('renders activity feed for user', async () => {
  server.use(http.get('/api/user/42', () => HttpResponse.json({ name: 'Ada' })))
  render(<UserProfile userId="42" />)
  expect(await screen.findByText('Ada')).toBeInTheDocument()
  expect(screen.getByRole('list', { name: /activity/i })).toBeInTheDocument()
})$escape$,
