INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c62838e4-b3a4-4871-9b2e-f7d1d51e9a6e',
  '00000000-0000-0000-0000-000000000001',
  $escape$vitest Async Testing — waitFor, findBy, and Fake Timers Done Right$escape$,
  $escape$vitest ships with full support for async testing patterns that pair directly with Testing Library. When asserting on elements that appear after an async operation, prefer `findBy*` queries over `getBy*` — they return a Promise and retry until the element appears or the timeout expires. For more complex async state changes, `waitFor` lets you wrap any assertion and poll until it passes, respecting vitest's default 1000ms timeout.

For code using `setTimeout` or `setInterval`, reach for `vi.useFakeTimers()`. After setting up fakes, call `vi.runAllTimers()` or `vi.advanceTimersByTime(ms)` to fast-forward without real delays. Always call `vi.useRealTimers()` in `afterEach` to prevent timer leakage between tests.

Avoid mixing `vi.useFakeTimers()` with `waitFor` — fake timers stall the polling loop inside `waitFor`. Instead, advance timers manually, then assert directly. For promise-based flows, `await vi.runAllTimersAsync()` (vitest 1.x+) drains the microtask queue alongside fake timers cleanly.$escape$,
  $escape$import { vi, describe, it, expect, afterEach } from 'vitest';
import { render, screen, waitFor } from '@testing-library/react';
import { AsyncCounter } from './AsyncCounter';

describe('AsyncCounter', () => {
  afterEach(() => vi.useRealTimers());

  it('increments after delay using fake timers', async () => {
    vi.useFakeTimers();
    render(<AsyncCounter />);

    await vi.runAllTimersAsync(); // drains setTimeout + microtasks
    expect(screen.getByText('Count: 1')).toBeInTheDocument();
  });

  it('finds element after fetch resolves', async () => {
    render(<AsyncCounter />);
    const el = await screen.findByText('Count: 1'); // retries up to 1000ms
    expect(el).toBeInTheDocument();
  });
});$escape$,
