INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b8f9ea8b-638d-440a-9af3-a8355df57677',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vitest Snapshot Testing — When It Helps vs When It Becomes Noise$escape$,
  $escape$Snapshot tests in Vitest shine for stable, serialized output — a utility that formats error objects, a pure transformer, or a small presentational component's rendered HTML. When the shape rarely changes, `toMatchSnapshot()` acts as a cheap regression net: it fails fast on unintended structural drift without hand-coding every assertion.

The noise starts when snapshots grow large, get auto-updated reflexively with `vitest -u`, or wrap components that change every sprint. A 300-line snapshot of a data table is meaningless in review — nobody reads it, reviewers approve blindly, and the test provides false confidence. Prefer `toMatchInlineSnapshot()` for small, intentional snapshots readable inline; bloated inline snapshots are immediately painful, which forces discipline.

Practical rule: if you're running `vitest --update-snapshots` more than once a week on the same file, replace those tests with targeted assertions like `expect(node.textContent).toBe(...)`. Snapshots should document stable contracts, not paper over missing assertions. The `__snapshots__` directory growing unchecked is a code smell, not a test suite.$escape$,
  $escape$import { render } from '@testing-library/react'
import { expect, test } from 'vitest'
import { Badge } from './Badge'

// Good: small, intentional — reviewable inline
test('Badge renders success variant', () => {
  const { container } = render(<Badge variant="success">Live</Badge>)
  expect(container.firstChild).toMatchInlineSnapshot(`
    <span class="badge badge--success">Live</span>
  `)
})

// Bad: large snapshot auto-updated with `vitest -u` — false safety
test('avoid: full dashboard snapshot nobody reads', () => {
  expect(render(<Dashboard />).container).toMatchSnapshot()
})$escape$,
