INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3ffd4d6b-cc64-4e88-abe4-e630dde74310',
  '00000000-0000-0000-0000-000000000001',
  $escape$vitest + Storybook: Visual Regression with Chromatic and the storybookTest Plugin$escape$,
  $escape$Storybook 8's `storybookTest` vitest plugin transforms your `.stories.tsx` files into native vitest test suites — no separate test runner needed. Configure a `storybook` project in `vitest.config.ts` with `browser.provider: 'playwright'` and every story executes headlessly via Chromium. Vitest validates interactions through `play()` functions using `@storybook/test`'s `userEvent` and `expect` wrappers, which delegate to vitest's own assertion engine under the hood.

For visual regression, wire Chromatic into CI after your vitest run. Chromatic snapshots every story on each push, diffs pixel changes across branches, and blocks PRs on unreviewed UI changes. Because stories already execute as vitest tests, a single CI step — `vitest run --project=storybook` — catches both interaction regressions and surfaces the component states Chromatic will diff.

Critical gotcha: set `browser.screenshotFailures: false` inside your storybook project config. Without it, vitest generates its own failure screenshots that conflict with Chromatic's baseline management, producing false positives in your diff queue.$escape$,
  $escape$// vitest.config.ts
import { defineConfig } from 'vitest/config'
import { storybookTest } from '@storybook/addon-vitest/plugin'

export default defineConfig({
  test: {
    projects: [{
      plugins: [storybookTest({ storiesGlob: 'src/**/*.stories.tsx' })],
      test: {
        name: 'storybook',
        browser: {
          enabled: true,
          headless: true,
          provider: 'playwright',
          instances: [{ browser: 'chromium' }],
          screenshotFailures: false, // let Chromatic own all diffs
        },
        setupFiles: ['.storybook/vitest.setup.ts'],
      },
    }],
  },
})$escape$,
