INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e6ef503c-8283-4ead-acd2-fd2f07825c9f',
  '00000000-0000-0000-0000-000000000001',
  $escape$vitest + axe-core — Automated Accessibility Checks Without a Browser$escape$,
  $escape$vitest runs in a jsdom environment, which means you can catch accessibility violations at unit-test speed using `@axe-core/react` or the lower-level `axe-core` directly via `jest-axe` (fully compatible with vitest). After rendering a component with `@testing-library/react`, pass the container to `axe()` and assert with `toHaveNoViolations()`. The matcher is added once in your `setupFiles` entry. This catches missing `aria-label` attributes, invalid roles, poor color contrast metadata, and heading hierarchy errors before they reach a browser. Scope scans to a specific subtree by passing `{ include: [['.modal']] }` as the axe options argument — this cuts noise when testing isolated components inside a larger DOM. Pair with `vitest`'s `test.each` to run the same a11y assertion across multiple prop variants (e.g., different button states: disabled, loading, error). Unlike Playwright a11y audits, this runs in-process with zero network overhead, making it practical to add to every component test file.$escape$,
  $escape$import { render } from '@testing-library/react';
import { axe, toHaveNoViolations } from 'jest-axe';
import { expect, test } from 'vitest';
import { Button } from './Button';

expect.extend(toHaveNoViolations);

test.each([
  { label: 'Submit', disabled: false },
  { label: 'Submit', disabled: true },
])('Button(%s) has no a11y violations', async (props) => {
  const { container } = render(<Button {...props} />);
  const results = await axe(container);
  expect(results).toHaveNoViolations();
});$escape$,
  $escape$typescript$escape$,
