INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd61cd723-8416-4eb2-a80d-0f817f5c8665',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vitest — Vite-Native Speed, Jest Compatibility, and In-Source Testing$escape$,
  $escape$Vitest runs inside Vite's dev server, sharing the same config, plugins, and module graph. That means zero cold-start overhead — your tests resolve the same aliases and transforms your app already uses, without a separate bundler pass.

The API is a deliberate Jest superset: `describe`, `it`, `expect`, `vi.fn()`, `vi.spyOn()`, and `vi.mock()` all behave as expected. Migration from Jest is usually a find-and-replace on imports — swap `jest` for `vi`.

The sharpest Vitest-exclusive feature is in-source testing. Add an `if (import.meta.vitest)` block directly inside your source file. Vitest strips it in production builds (Vite tree-shakes it), but executes it during test runs. This keeps unit tests physically co-located with the function they test — no separate spec file needed for pure utilities.

Pair in-source tests with `globals: true` in `vitest.config.ts` to drop the `import { it, expect } from 'vitest'` boilerplate inside those blocks. Use `pool: 'vmThreads'` for faster parallelism over the default `forks` pool on CPU-bound suites.$escape$,
  $escape$// src/utils/clamp.ts
export function clamp(value: number, min: number, max: number) {
  return Math.min(Math.max(value, min), max);
}

// In-source test — stripped from production bundle by Vite
if (import.meta.vitest) {
  const { it, expect } = import.meta.vitest;
  it('clamps within bounds', () => {
    expect(clamp(150, 0, 100)).toBe(100);
    expect(clamp(-5, 0, 100)).toBe(0);
    expect(clamp(42, 0, 100)).toBe(42);
  });
}$escape$,
