INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3c8652e7-21f5-4257-be8e-5d44f1efc35c',
  '00000000-0000-0000-0000-000000000001',
  $escape$vitest Browser Mode — Multi-Browser, Traces, and Real Network Interception with Playwright$escape$,
  $escape$Vitest's browser mode (`@vitest/browser`) runs tests inside a real browser using Playwright as the provider — giving you access to Playwright's full API surface directly in your test files. Configure `instances` in `vitest.config.ts` to fan out a single test suite across Chromium, Firefox, and WebKit simultaneously, with results aggregated per-browser in the terminal.

Network interception works via the `page` fixture from `@vitest/browser/context`. Call `page.route()` before rendering your component — Playwright intercepts at the actual network layer, not via module mocking. This catches issues `vi.mock('fetch')` cannot: malformed response handling, redirect chains, and CORS edge cases.

Traces are captured with `providerOptions.launch.tracesDir` in your vitest config. When a test fails, open it with `npx playwright show-trace .vitest-traces/<name>.zip` — you get DOM snapshots, network waterfall, and console logs at every step. Pair with `--reporter=html` to correlate vitest's test output with the trace timeline.$escape$,
  $escape$// vitest.config.ts
export default defineConfig({
  test: {
    browser: {
      enabled: true,
      provider: 'playwright',
      instances: [
        { browser: 'chromium' },
        { browser: 'firefox' },
        { browser: 'webkit' },
      ],
      providerOptions: { launch: { tracesDir: '.vitest-traces' } },
    },
  },
})

// UserList.test.tsx
import { page } from '@vitest/browser/context'

test('handles empty state across browsers', async () => {
  await page.route('/api/users', route =>
    route.fulfill({ json: [], status: 200 })
  )
  const { getByText } = render(<UserList />)
  await expect.element(getByText('No users found')).toBeVisible()
})$escape$,
