INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a4e42631-1535-4e7e-aee4-db32ab34d237',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vitest Browser Mode — Component Testing and the cy.intercept Equivalent$escape$,
  $escape$Vitest's browser mode (`@vitest/browser`) runs component tests in a real Chromium/Firefox/WebKit instance via Playwright or WebdriverIO, mirroring Cypress's component testing mode. But there's no `cy.intercept` equivalent built in — network mocking falls to MSW.

In jsdom mode (the default), `setupServer` from `msw/node` intercepts fetch at the Node layer. In true browser mode, you need `setupWorker` with a registered service worker, or the `vitest-msw` integration that handles worker setup automatically.

Critical difference from Cypress: `vi.mock` cannot intercept real HTTP calls in browser mode — it only stubs ES module imports. For any component that calls `fetch` or `axios`, MSW is the correct interception layer.

Handler scoping follows the same `beforeAll / afterEach / afterAll` pattern as Jest + MSW, so the mental model transfers cleanly. Override handlers per-test with `server.use(...)` to simulate error or loading states — the direct vitest equivalent of a `cy.intercept` override scoped inside an `it` block.$escape$,
  $escape$import { render, screen, waitFor } from '@testing-library/react'
import { http, HttpResponse } from 'msw'
import { setupServer } from 'msw/node'
import { UserCard } from './UserCard'

const server = setupServer(
  http.get('/api/user', () =>
    HttpResponse.json({ name: 'Ada Lovelace' })
  )
)

beforeAll(() => server.listen())
afterEach(() => server.resetHandlers())
afterAll(() => server.close())

it('renders user from intercepted fetch', async () => {
  render(<UserCard />)
  await waitFor(() =>
    expect(screen.getByText('Ada Lovelace')).toBeInTheDocument()
  )
})$escape$,
