INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9e2c5ec2-e4e0-4f62-97ee-992edfd76ce8',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vitest Code Coverage — What It Tells You and What It Doesn't$escape$,
  $escape$Running `vitest --coverage` with `@vitest/coverage-v8` gives you line, branch, function, and statement metrics — but 100% coverage is not a correctness guarantee. Coverage measures execution paths hit, not assertions made. A test that calls a function without `expect()` inflates your numbers while catching nothing.

The real trap is branch coverage theater. A ternary with both arms covered doesn't mean your logic is correct — it means both paths ran. Use `coverage.thresholds` in `vitest.config.ts` to enforce minimums, but pair it with meaningful assertions.

Vitest's `coverage.include` and `coverage.exclude` let you scope reports precisely — exclude generated files, route manifests, and index re-exports that add noise. Focus threshold enforcement on `src/lib` and `src/hooks` where logic lives.

The `all: true` option under `coverage` forces uncovered files into the report — critical for spotting dead code that tests never import. Without it, a file with zero tests simply disappears from your metrics, silently inflating your score.$escape$,
  $escape$// vitest.config.ts
import { defineConfig } from 'vitest/config'

export default defineConfig({
  test: {
    coverage: {
      provider: 'v8',
      all: true,
      include: ['src/lib/**', 'src/hooks/**'],
      exclude: ['src/**/*.stories.ts', 'src/generated/**'],
      thresholds: {
        lines: 80,
        branches: 75,
        functions: 80,
        statements: 80,
      },
    },
  },
})$escape$,
  $escape$typescript$escape$,
